import json

before = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def get_packages(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = get_packages(before)
a = get_packages(after)

print('=== CHANGES ===')
changes = False
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(key, 'N/A')
    av = a.get(key, 'N/A')
    if bv != av:
        changes = True
        print(f'{key[0]} | {key[1]} | {key[2]} | {bv} -> {av}')

if not changes:
    print('(none)')

print()
print('=== UNCHANGED ===')
for key in sorted(b.keys()):
    if b[key] == a.get(key):
        print(f'{key[0]} | {key[1]} | {key[2]} | {b[key]}')
"

